package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsSet() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(format.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerSetToNullCharacter() {
        // Using withCommentMarker(Character) with null disables comment marker
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertFalse(format.isCommentMarkerSet());
    }
}
